import { useState, useEffect, useRef } from 'react';
import { useParams } from 'react-router-dom';
import { useTranslation } from 'react-i18next';
import { studyApi, imageApi } from '@/services/api';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import {
  ZoomIn,
  ZoomOut,
  RotateCw,
  FlipHorizontal,
  FlipVertical,
  Maximize,
  Move,
  Ruler,
  Type,
  Square,
  Circle,
  Layers,
  Sliders,
  Columns,
} from 'lucide-react';

interface Study {
  id: string;
  patientId: string;
  studyDate: string;
  studyType: string;
  modality: string;
  status: string;
}

interface Image {
  id: string;
  filePath: string;
  thumbnailPath?: string;
  width: number;
  height: number;
  format: string;
}

export function ViewerPage() {
  const { studyId } = useParams<{ studyId: string }>();
  const { t } = useTranslation();
  const [study, setStudy] = useState<Study | null>(null);
  const [images, setImages] = useState<Image[]>([]);
  const [selectedImage, setSelectedImage] = useState<Image | null>(null);
  const [loading, setLoading] = useState(true);
  const [activeTool, setActiveTool] = useState<string>('pan');
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    if (studyId) {
      loadStudy(studyId);
      loadImages(studyId);
    }
  }, [studyId]);

  const loadStudy = async (id: string) => {
    try {
      const response = await studyApi.getById(id);
      setStudy(response.data);
    } catch (error) {
      console.error('Failed to load study:', error);
    }
  };

  const loadImages = async (id: string) => {
    try {
      const seriesResponse = await studyApi.getSeries(id);
      const series = seriesResponse.data || [];
      if (series.length > 0) {
        // Load images from first series
        const imagesResponse = await imageApi.search({ seriesId: series[0].id });
        setImages(imagesResponse.data || []);
        if (imagesResponse.data?.length > 0) {
          setSelectedImage(imagesResponse.data[0]);
        }
      }
    } catch (error) {
      console.error('Failed to load images:', error);
    } finally {
      setLoading(false);
    }
  };

  const tools = [
    { id: 'pan', icon: Move, label: t('viewer.pan') },
    { id: 'zoom', icon: ZoomIn, label: t('viewer.zoom') },
    { id: 'rotate', icon: RotateCw, label: t('viewer.rotate') },
    { id: 'flipH', icon: FlipHorizontal, label: '水平翻转' },
    { id: 'flipV', icon: FlipVertical, label: '垂直翻转' },
    { id: 'fit', icon: Maximize, label: '适配窗口' },
    { id: 'measure', icon: Ruler, label: t('viewer.measure') },
    { id: 'annotate', icon: Type, label: t('viewer.annotate') },
    { id: 'rect', icon: Square, label: '矩形ROI' },
    { id: 'ellipse', icon: Circle, label: '椭圆ROI' },
  ];

  if (loading) {
    return <div className="text-center py-8">加载中...</div>;
  }

  return (
    <div className="flex h-[calc(100vh-8rem)] space-x-4">
      {/* Main viewer */}
      <div className="flex-1 flex flex-col">
        {/* Toolbar */}
        <Card className="mb-4">
          <CardContent className="p-2">
            <div className="flex items-center space-x-1">
              {tools.map((tool) => {
                const Icon = tool.icon;
                return (
                  <Button
                    key={tool.id}
                    variant={activeTool === tool.id ? 'default' : 'ghost'}
                    size="icon"
                    onClick={() => setActiveTool(tool.id)}
                    title={tool.label}
                  >
                    <Icon className="h-4 w-4" />
                  </Button>
                );
              })}
              <div className="mx-2 h-6 w-px bg-border" />
              <Button variant="ghost" size="icon" title={t('viewer.layers')}>
                <Layers className="h-4 w-4" />
              </Button>
              <Button variant="ghost" size="icon" title={t('viewer.filters')}>
                <Sliders className="h-4 w-4" />
              </Button>
              <Button variant="ghost" size="icon" title={t('viewer.compare')}>
                <Columns className="h-4 w-4" />
              </Button>
            </div>
          </CardContent>
        </Card>

        {/* Image canvas */}
        <Card className="flex-1">
          <CardContent className="p-0 h-full">
            <div className="relative h-full flex items-center justify-center bg-black">
              {selectedImage ? (
                <canvas
                  ref={canvasRef}
                  className="max-h-full max-w-full"
                  width={selectedImage.width}
                  height={selectedImage.height}
                />
              ) : (
                <div className="text-muted-foreground">请选择图像</div>
              )}
            </div>
          </CardContent>
        </Card>

        {/* Image info */}
        <Card className="mt-4">
          <CardContent className="p-2">
            <div className="flex items-center justify-between text-sm text-muted-foreground">
              <span>
                {selectedImage
                  ? `${selectedImage.width} x ${selectedImage.height} | ${selectedImage.format.toUpperCase()}`
                  : '-'}
              </span>
              <span>
                {selectedImage ? `1 / ${images.length}` : '-'}
              </span>
            </div>
          </CardContent>
        </Card>
      </div>

      {/* Sidebar */}
      <div className="w-80 flex flex-col space-y-4">
        {/* Study info */}
        <Card>
          <CardHeader className="pb-2">
            <CardTitle className="text-sm">检查信息</CardTitle>
          </CardHeader>
          <CardContent>
            {study && (
              <div className="space-y-2 text-sm">
                <div className="flex justify-between">
                  <span className="text-muted-foreground">检查类型</span>
                  <span>{study.studyType.toUpperCase()}</span>
                </div>
                <div className="flex justify-between">
                  <span className="text-muted-foreground">检查日期</span>
                  <span>{study.studyDate}</span>
                </div>
                <div className="flex justify-between">
                  <span className="text-muted-foreground">模态</span>
                  <span>{study.modality}</span>
                </div>
                <div className="flex justify-between">
                  <span className="text-muted-foreground">状态</span>
                  <span>{study.status}</span>
                </div>
              </div>
            )}
          </CardContent>
        </Card>

        {/* Image list */}
        <Card className="flex-1 overflow-hidden">
          <CardHeader className="pb-2">
            <CardTitle className="text-sm">图像列表</CardTitle>
          </CardHeader>
          <CardContent className="p-0 overflow-y-auto max-h-[400px]">
            <div className="grid grid-cols-3 gap-1 p-2">
              {images.map((image, index) => (
                <button
                  key={image.id}
                  className={`relative aspect-square overflow-hidden rounded border-2 transition-colors ${
                    selectedImage?.id === image.id
                      ? 'border-primary'
                      : 'border-transparent hover:border-primary/50'
                  }`}
                  onClick={() => setSelectedImage(image)}
                >
                  {image.thumbnailPath ? (
                    <img
                      src={image.thumbnailPath}
                      alt={`Image ${index + 1}`}
                      className="h-full w-full object-cover"
                    />
                  ) : (
                    <div className="flex h-full w-full items-center justify-center bg-muted text-xs text-muted-foreground">
                      {index + 1}
                    </div>
                  )}
                </button>
              ))}
            </div>
          </CardContent>
        </Card>

        {/* Window/Level */}
        <Card>
          <CardHeader className="pb-2">
            <CardTitle className="text-sm">{t('viewer.windowLevel')}</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="space-y-4">
              <div>
                <div className="flex justify-between text-sm mb-1">
                  <span>窗宽</span>
                  <span>400</span>
                </div>
                <input type="range" className="w-full" min="1" max="4096" defaultValue="400" />
              </div>
              <div>
                <div className="flex justify-between text-sm mb-1">
                  <span>窗位</span>
                  <span>40</span>
                </div>
                <input type="range" className="w-full" min="-1024" max="3072" defaultValue="40" />
              </div>
            </div>
          </CardContent>
        </Card>
      </div>
    </div>
  );
}

