import { useRef, useEffect, useCallback } from 'react';
import { cn } from '@/lib/utils';

interface ImageListProps {
  images: Array<{
    id: string;
    filePath: string;
    thumbnailPath?: string;
    width: number;
    height: number;
    format: string;
  }>;
  selectedImageId: string | null;
  onSelectImage: (imageId: string) => void;
  className?: string;
}

export function ImageList({
  images,
  selectedImageId,
  onSelectImage,
  className,
}: ImageListProps) {
  const listRef = useRef<HTMLDivElement>(null);
  const selectedRef = useRef<HTMLButtonElement>(null);

  useEffect(() => {
    if (selectedRef.current && listRef.current) {
      selectedRef.current.scrollIntoView({
        behavior: 'smooth',
        block: 'nearest',
      });
    }
  }, [selectedImageId]);

  const handleKeyDown = useCallback(
    (e: React.KeyboardEvent) => {
      if (!images.length) return;

      const currentIndex = images.findIndex((img) => img.id === selectedImageId);
      if (currentIndex === -1) return;

      let newIndex = currentIndex;

      switch (e.key) {
        case 'ArrowUp':
        case 'ArrowLeft':
          e.preventDefault();
          newIndex = Math.max(0, currentIndex - 1);
          break;
        case 'ArrowDown':
        case 'ArrowRight':
          e.preventDefault();
          newIndex = Math.min(images.length - 1, currentIndex + 1);
          break;
        case 'Home':
          e.preventDefault();
          newIndex = 0;
          break;
        case 'End':
          e.preventDefault();
          newIndex = images.length - 1;
          break;
      }

      if (newIndex !== currentIndex) {
        onSelectImage(images[newIndex].id);
      }
    },
    [images, selectedImageId, onSelectImage]
  );

  if (images.length === 0) {
    return (
      <div className={cn('flex items-center justify-center p-4 text-muted-foreground', className)}>
        暂无图像
      </div>
    );
  }

  return (
    <div
      ref={listRef}
      className={cn('grid grid-cols-3 gap-1 p-2 overflow-y-auto', className)}
      onKeyDown={handleKeyDown}
      tabIndex={0}
      role="listbox"
      aria-label="图像列表"
      aria-orientation="vertical"
    >
      {images.map((image, index) => {
        const isSelected = image.id === selectedImageId;
        return (
          <button
            key={image.id}
            ref={isSelected ? selectedRef : null}
            className={cn(
              'relative aspect-square overflow-hidden rounded border-2 transition-all',
              'focus:outline-none focus:ring-2 focus:ring-primary focus:ring-offset-2',
              isSelected
                ? 'border-primary shadow-lg scale-105'
                : 'border-transparent hover:border-primary/50 hover:scale-102'
            )}
            onClick={() => onSelectImage(image.id)}
            role="option"
            aria-selected={isSelected}
            aria-label={`图像 ${index + 1}`}
            title={`${image.width} x ${image.height} | ${image.format.toUpperCase()}`}
          >
            {image.thumbnailPath ? (
              <img
                src={image.thumbnailPath}
                alt={`图像 ${index + 1}`}
                className="h-full w-full object-cover"
                loading="lazy"
              />
            ) : (
              <div className="flex h-full w-full items-center justify-center bg-muted text-xs text-muted-foreground">
                {index + 1}
              </div>
            )}
            {isSelected && (
              <div className="absolute inset-0 bg-primary/10 ring-2 ring-primary rounded" />
            )}
            <div className="absolute bottom-0 left-0 right-0 bg-black/50 text-white text-xs text-center py-0.5">
              {index + 1}
            </div>
          </button>
        );
      })}
    </div>
  );
}

import { useCallback } from 'react';
import { cn } from '@/lib/utils';
import { Button } from '@/components/ui/button';
import {
  ZoomIn,
  ZoomOut,
  RotateCw,
  FlipHorizontal,
  FlipVertical,
  Maximize,
  Move,
  Ruler,
  Type,
  Square,
  Circle,
  Layers,
  Sliders,
  Columns,
  Undo,
  Redo,
  Trash2,
} from 'lucide-react';

export type ToolType =
  | 'pan'
  | 'zoom'
  | 'rotate'
  | 'flipH'
  | 'flipV'
  | 'fit'
  | 'windowLevel'
  | 'measure'
  | 'annotate'
  | 'rect'
  | 'ellipse'
  | 'freehand';

export interface ToolbarProps {
  activeTool: ToolType;
  onToolChange: (tool: ToolType) => void;
  onZoomIn?: () => void;
  onZoomOut?: () => void;
  onRotate?: () => void;
  onFlipH?: () => void;
  onFlipV?: () => void;
  onFitToWindow?: () => void;
  onReset?: () => void;
  onUndo?: () => void;
  onRedo?: () => void;
  onDelete?: () => void;
  onToggleLayers?: () => void;
  onToggleFilters?: () => void;
  onToggleCompare?: () => void;
  className?: string;
}

const mainTools = [
  { id: 'pan' as ToolType, icon: Move, label: '平移', shortcut: 'P' },
  { id: 'zoom' as ToolType, icon: ZoomIn, label: '缩放', shortcut: 'Z' },
  { id: 'windowLevel' as ToolType, icon: Sliders, label: '窗宽窗位', shortcut: 'W' },
];

const measureTools = [
  { id: 'measure' as ToolType, icon: Ruler, label: '测量', shortcut: 'M' },
  { id: 'annotate' as ToolType, icon: Type, label: '标注', shortcut: 'A' },
  { id: 'rect' as ToolType, icon: Square, label: '矩形ROI', shortcut: 'R' },
  { id: 'ellipse' as ToolType, icon: Circle, label: '椭圆ROI', shortcut: 'E' },
];

const actionButtons = [
  { id: 'rotate' as ToolType, icon: RotateCw, label: '旋转', shortcut: 'Ctrl+R' },
  { id: 'flipH' as ToolType, icon: FlipHorizontal, label: '水平翻转', shortcut: 'H' },
  { id: 'flipV' as ToolType, icon: FlipVertical, label: '垂直翻转', shortcut: 'V' },
  { id: 'fit' as ToolType, icon: Maximize, label: '适配窗口', shortcut: 'F' },
];

export function Toolbar({
  activeTool,
  onToolChange,
  onZoomIn,
  onZoomOut,
  onRotate,
  onFlipH,
  onFlipV,
  onFitToWindow,
  onReset,
  onUndo,
  onRedo,
  onDelete,
  onToggleLayers,
  onToggleFilters,
  onToggleCompare,
  className,
}: ToolbarProps) {
  const handleToolClick = useCallback(
    (tool: ToolType) => {
      onToolChange(tool);

      switch (tool) {
        case 'rotate':
          onRotate?.();
          break;
        case 'flipH':
          onFlipH?.();
          break;
        case 'flipV':
          onFlipV?.();
          break;
        case 'fit':
          onFitToWindow?.();
          break;
      }
    },
    [onToolChange, onRotate, onFlipH, onFlipV, onFitToWindow]
  );

  const ToolButton = ({
    tool,
    icon: Icon,
    label,
    shortcut,
  }: {
    tool: ToolType;
    icon: any;
    label: string;
    shortcut?: string;
  }) => (
    <Button
      variant={activeTool === tool ? 'default' : 'ghost'}
      size="icon"
      onClick={() => handleToolClick(tool)}
      title={`${label}${shortcut ? ` (${shortcut})` : ''}`}
      aria-label={label}
      aria-pressed={activeTool === tool}
    >
      <Icon className="h-4 w-4" />
    </Button>
  );

  const ActionButton = ({
    icon: Icon,
    label,
    onClick,
    disabled = false,
  }: {
    icon: any;
    label: string;
    onClick?: () => void;
    disabled?: boolean;
  }) => (
    <Button
      variant="ghost"
      size="icon"
      onClick={onClick}
      disabled={disabled}
      title={label}
      aria-label={label}
    >
      <Icon className="h-4 w-4" />
    </Button>
  );

  return (
    <div
      className={cn(
        'flex items-center space-x-1 p-2 bg-card border-b',
        className
      )}
      role="toolbar"
      aria-label="图像工具栏"
    >
      {/* Main tools */}
      <div className="flex items-center space-x-1" role="group" aria-label="主要工具">
        {mainTools.map((tool) => (
          <ToolButton key={tool.id} {...tool} />
        ))}
      </div>

      <div className="mx-1 h-6 w-px bg-border" role="separator" />

      {/* Measurement tools */}
      <div className="flex items-center space-x-1" role="group" aria-label="测量工具">
        {measureTools.map((tool) => (
          <ToolButton key={tool.id} {...tool} />
        ))}
      </div>

      <div className="mx-1 h-6 w-px bg-border" role="separator" />

      {/* Action buttons */}
      <div className="flex items-center space-x-1" role="group" aria-label="操作">
        {actionButtons.map((tool) => (
          <ToolButton key={tool.id} {...tool} />
        ))}
      </div>

      <div className="mx-1 h-6 w-px bg-border" role="separator" />

      {/* Undo/Redo/Delete */}
      <div className="flex items-center space-x-1" role="group" aria-label="编辑">
        <ActionButton icon={Undo} label="撤销" onClick={onUndo} />
        <ActionButton icon={Redo} label="重做" onClick={onRedo} />
        <ActionButton icon={Trash2} label="删除" onClick={onDelete} />
      </div>

      <div className="flex-1" />

      {/* Panel toggles */}
      <div className="flex items-center space-x-1" role="group" aria-label="面板">
        <ActionButton icon={Layers} label="图层" onClick={onToggleLayers} />
        <ActionButton icon={Sliders} label="滤镜" onClick={onToggleFilters} />
        <ActionButton icon={Columns} label="对比" onClick={onToggleCompare} />
      </div>
    </div>
  );
}

import { useState, useEffect, useRef, useCallback } from 'react';
import { cn } from '@/lib/utils';
import { Toolbar, type ToolType } from './Toolbar';

export interface ImageViewerImage {
  id: string;
  filePath: string;
  thumbnailPath?: string;
  width: number;
  height: number;
  format: string;
  metadata?: Record<string, any>;
}

export interface ImageViewerProps {
  image: ImageViewerImage | null;
  images?: ImageViewerImage[];
  onImageChange?: (image: ImageViewerImage) => void;
  className?: string;
}

interface ViewportState {
  zoom: number;
  pan: { x: number; y: number };
  rotation: number;
  flipH: boolean;
  flipV: boolean;
  windowWidth: number;
  windowCenter: number;
}

const defaultViewportState: ViewportState = {
  zoom: 1,
  pan: { x: 0, y: 0 },
  rotation: 0,
  flipH: false,
  flipV: false,
  windowWidth: 400,
  windowCenter: 40,
};

export function ImageViewer({
  image,
  images = [],
  onImageChange,
  className,
}: ImageViewerProps) {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const [activeTool, setActiveTool] = useState<ToolType>('pan');
  const [viewport, setViewport] = useState<ViewportState>(defaultViewportState);
  const [isDragging, setIsDragging] = useState(false);
  const [dragStart, setDragStart] = useState({ x: 0, y: 0 });
  const [imageLoaded, setImageLoaded] = useState(false);
  const [loading, setLoading] = useState(false);
  const imageRef = useRef<HTMLImageElement | null>(null);

  const loadAndRenderImage = useCallback(async () => {
    if (!image || !canvasRef.current) return;

    setLoading(true);
    setImageLoaded(false);

    try {
      const img = new Image();
      img.crossOrigin = 'anonymous';

      await new Promise<void>((resolve, reject) => {
        img.onload = () => resolve();
        img.onerror = reject;
        img.src = `/api/images/${image.id}/file`;
      });

      imageRef.current = img;
      setImageLoaded(true);
      renderImage(img);
    } catch (error) {
      console.error('Failed to load image:', error);
    } finally {
      setLoading(false);
    }
  }, [image]);

  useEffect(() => {
    loadAndRenderImage();
  }, [loadAndRenderImage]);

  useEffect(() => {
    if (imageRef.current && imageLoaded) {
      renderImage(imageRef.current);
    }
  }, [viewport, imageLoaded]);

  const renderImage = useCallback(
    (img: HTMLImageElement) => {
      const canvas = canvasRef.current;
      if (!canvas) return;

      const ctx = canvas.getContext('2d');
      if (!ctx) return;

      const container = containerRef.current;
      if (!container) return;

      const containerWidth = container.clientWidth;
      const containerHeight = container.clientHeight;

      canvas.width = containerWidth;
      canvas.height = containerHeight;

      ctx.clearRect(0, 0, containerWidth, containerHeight);
      ctx.save();

      ctx.translate(containerWidth / 2, containerHeight / 2);

      ctx.scale(viewport.zoom, viewport.zoom);
      ctx.translate(viewport.pan.x, viewport.pan.y);
      ctx.rotate((viewport.rotation * Math.PI) / 180);
      ctx.scale(viewport.flipH ? -1 : 1, viewport.flipV ? -1 : 1);

      const scale = Math.min(
        containerWidth / img.width,
        containerHeight / img.height
      );
      const width = img.width * scale;
      const height = img.height * scale;

      ctx.drawImage(img, -width / 2, -height / 2, width, height);

      ctx.restore();
    },
    [viewport]
  );

  const handleMouseDown = useCallback(
    (e: React.MouseEvent<HTMLCanvasElement>) => {
      if (!image) return;

      setIsDragging(true);
      setDragStart({ x: e.clientX, y: e.clientY });

      if (activeTool === 'windowLevel') {
        setDragStart({ x: e.clientX, y: e.clientY });
      }
    },
    [image, activeTool]
  );

  const handleMouseMove = useCallback(
    (e: React.MouseEvent<HTMLCanvasElement>) => {
      if (!isDragging || !image) return;

      const deltaX = e.clientX - dragStart.x;
      const deltaY = e.clientY - dragStart.y;

      switch (activeTool) {
        case 'pan':
          setViewport((prev) => ({
            ...prev,
            pan: {
              x: prev.pan.x + deltaX / prev.zoom,
              y: prev.pan.y + deltaY / prev.zoom,
            },
          }));
          break;

        case 'zoom':
          const zoomFactor = 1 + deltaY * 0.005;
          setViewport((prev) => ({
            ...prev,
            zoom: Math.max(0.1, Math.min(10, prev.zoom * zoomFactor)),
          }));
          break;

        case 'windowLevel':
          setViewport((prev) => ({
            ...prev,
            windowWidth: Math.max(1, prev.windowWidth + deltaX),
            windowCenter: prev.windowCenter + deltaY,
          }));
          break;
      }

      setDragStart({ x: e.clientX, y: e.clientY });
    },
    [isDragging, dragStart, activeTool, image]
  );

  const handleMouseUp = useCallback(() => {
    setIsDragging(false);
  }, []);

  const handleWheel = useCallback(
    (e: React.WheelEvent<HTMLCanvasElement>) => {
      e.preventDefault();
      const zoomFactor = e.deltaY > 0 ? 0.95 : 1.05;
      setViewport((prev) => ({
        ...prev,
        zoom: Math.max(0.1, Math.min(10, prev.zoom * zoomFactor)),
      }));
    },
    []
  );

  const handleZoomIn = useCallback(() => {
    setViewport((prev) => ({
      ...prev,
      zoom: Math.min(10, prev.zoom * 1.2),
    }));
  }, []);

  const handleZoomOut = useCallback(() => {
    setViewport((prev) => ({
      ...prev,
      zoom: Math.max(0.1, prev.zoom / 1.2),
    }));
  }, []);

  const handleRotate = useCallback(() => {
    setViewport((prev) => ({
      ...prev,
      rotation: (prev.rotation + 90) % 360,
    }));
  }, []);

  const handleFlipH = useCallback(() => {
    setViewport((prev) => ({
      ...prev,
      flipH: !prev.flipH,
    }));
  }, []);

  const handleFlipV = useCallback(() => {
    setViewport((prev) => ({
      ...prev,
      flipV: !prev.flipV,
    }));
  }, []);

  const handleFitToWindow = useCallback(() => {
    setViewport((prev) => ({
      ...prev,
      zoom: 1,
      pan: { x: 0, y: 0 },
      rotation: 0,
      flipH: false,
      flipV: false,
    }));
  }, []);

  const handleReset = useCallback(() => {
    setViewport(defaultViewportState);
  }, []);

  const handleKeyDown = useCallback(
    (e: React.KeyboardEvent) => {
      switch (e.key) {
        case 'p':
        case 'P':
          setActiveTool('pan');
          break;
        case 'z':
        case 'Z':
          setActiveTool('zoom');
          break;
        case 'w':
        case 'W':
          setActiveTool('windowLevel');
          break;
        case 'm':
        case 'M':
          setActiveTool('measure');
          break;
        case 'a':
        case 'A':
          setActiveTool('annotate');
          break;
        case '+':
        case '=':
          handleZoomIn();
          break;
        case '-':
          handleZoomOut();
          break;
        case 'r':
        case 'R':
          if (e.ctrlKey || e.metaKey) {
            e.preventDefault();
            handleRotate();
          }
          break;
        case 'h':
        case 'H':
          handleFlipH();
          break;
        case 'v':
        case 'V':
          handleFlipV();
          break;
        case 'f':
        case 'F':
          handleFitToWindow();
          break;
        case 'Escape':
          setActiveTool('pan');
          break;
      }
    },
    [handleZoomIn, handleZoomOut, handleRotate, handleFlipH, handleFlipV, handleFitToWindow]
  );

  const handleImageSelect = useCallback(
    (imageId: string) => {
      const selected = images.find((img) => img.id === imageId);
      if (selected && onImageChange) {
        onImageChange(selected);
      }
    },
    [images, onImageChange]
  );

  const getCursorStyle = () => {
    switch (activeTool) {
      case 'pan':
        return isDragging ? 'grabbing' : 'grab';
      case 'zoom':
        return 'zoom-in';
      case 'windowLevel':
        return 'crosshair';
      case 'measure':
      case 'annotate':
      case 'rect':
      case 'ellipse':
        return 'crosshair';
      default:
        return 'default';
    }
  };

  return (
    <div
      className={cn('flex flex-col h-full', className)}
      onKeyDown={handleKeyDown}
      tabIndex={0}
    >
      <Toolbar
        activeTool={activeTool}
        onToolChange={setActiveTool}
        onZoomIn={handleZoomIn}
        onZoomOut={handleZoomOut}
        onRotate={handleRotate}
        onFlipH={handleFlipH}
        onFlipV={handleFlipV}
        onFitToWindow={handleFitToWindow}
        onReset={handleReset}
      />

      <div className="flex-1 relative bg-black" ref={containerRef}>
        {loading && (
          <div className="absolute inset-0 flex items-center justify-center bg-black/50 z-10">
            <div className="text-white">加载中...</div>
          </div>
        )}

        {!image && !loading && (
          <div className="absolute inset-0 flex items-center justify-center text-muted-foreground">
            请选择图像
          </div>
        )}

        <canvas
          ref={canvasRef}
          className={cn(
            'w-full h-full',
            image ? 'cursor-' + getCursorStyle() : 'cursor-default'
          )}
          style={{ cursor: image ? getCursorStyle() : 'default' }}
          onMouseDown={handleMouseDown}
          onMouseMove={handleMouseMove}
          onMouseUp={handleMouseUp}
          onMouseLeave={handleMouseUp}
          onWheel={handleWheel}
          aria-label="图像查看器"
          role="img"
        />
      </div>

      {image && (
        <div className="flex items-center justify-between p-2 text-sm text-muted-foreground bg-card border-t">
          <div className="flex items-center space-x-4">
            <span>{image.width} × {image.height}</span>
            <span>{image.format.toUpperCase()}</span>
            <span>缩放: {Math.round(viewport.zoom * 100)}%</span>
            <span>旋转: {viewport.rotation}°</span>
          </div>
          <div className="flex items-center space-x-4">
            <span>窗宽: {Math.round(viewport.windowWidth)}</span>
            <span>窗位: {Math.round(viewport.windowCenter)}</span>
          </div>
        </div>
      )}
    </div>
  );
}

export { ImageViewer } from './ImageViewer';
export type { ImageViewerProps, ImageViewerImage } from './ImageViewer';

export { Toolbar } from './Toolbar';
export type { ToolbarProps, ToolType } from './Toolbar';

export { ImageList } from './ImageList';

import { useState, useEffect } from 'react';
import { useParams } from 'react-router-dom';
import { useTranslation } from 'react-i18next';
import { studyApi, imageApi } from '@/services/api';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { ImageViewer, type ImageViewerImage } from '@/components/viewer';
import { ImageList } from '@/components/viewer/ImageList';

interface Study {
  id: string;
  patientId: string;
  studyDate: string;
  studyType: string;
  modality: string;
  status: string;
}

export function ViewerPage() {
  const { studyId } = useParams<{ studyId: string }>();
  const { t } = useTranslation();
  const [study, setStudy] = useState<Study | null>(null);
  const [images, setImages] = useState<ImageViewerImage[]>([]);
  const [selectedImage, setSelectedImage] = useState<ImageViewerImage | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (studyId) {
      loadStudy(studyId);
      loadImages(studyId);
    }
  }, [studyId]);

  const loadStudy = async (id: string) => {
    try {
      const response = await studyApi.getById(id);
      setStudy(response.data);
    } catch (error) {
      console.error('Failed to load study:', error);
    }
  };

  const loadImages = async (id: string) => {
    try {
      const seriesResponse = await studyApi.getSeries(id);
      const series = seriesResponse.data || [];
      if (series.length > 0) {
        const imagesResponse = await imageApi.search({ seriesId: series[0].id });
        const imageData = imagesResponse.data || [];
        setImages(imageData);
        if (imageData.length > 0) {
          setSelectedImage(imageData[0]);
        }
      }
    } catch (error) {
      console.error('Failed to load images:', error);
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center h-[calc(100vh-8rem)]">
        <div className="text-muted-foreground">加载中...</div>
      </div>
    );
  }

  return (
    <div className="flex h-[calc(100vh-8rem)] space-x-4">
      {/* Main viewer */}
      <div className="flex-1 flex flex-col">
        <Card className="flex-1">
          <CardContent className="p-0 h-full">
            <ImageViewer
              image={selectedImage}
              images={images}
              onImageChange={setSelectedImage}
              className="h-full"
            />
          </CardContent>
        </Card>
      </div>

      {/* Sidebar */}
      <div className="w-80 flex flex-col space-y-4">
        {/* Study info */}
        <Card>
          <CardHeader className="pb-2">
            <CardTitle className="text-sm">检查信息</CardTitle>
          </CardHeader>
          <CardContent>
            {study && (
              <div className="space-y-2 text-sm">
                <div className="flex justify-between">
                  <span className="text-muted-foreground">检查类型</span>
                  <span>{study.studyType.toUpperCase()}</span>
                </div>
                <div className="flex justify-between">
                  <span className="text-muted-foreground">检查日期</span>
                  <span>{study.studyDate}</span>
                </div>
                <div className="flex justify-between">
                  <span className="text-muted-foreground">模态</span>
                  <span>{study.modality}</span>
                </div>
                <div className="flex justify-between">
                  <span className="text-muted-foreground">状态</span>
                  <span>{study.status}</span>
                </div>
              </div>
            )}
          </CardContent>
        </Card>

        {/* Image list */}
        <Card className="flex-1 overflow-hidden">
          <CardHeader className="pb-2">
            <CardTitle className="text-sm">图像列表</CardTitle>
          </CardHeader>
          <CardContent className="p-0 overflow-y-auto max-h-[400px]">
            <ImageList
              images={images}
              selectedImageId={selectedImage?.id || null}
              onSelectImage={(imageId) => {
                const img = images.find((i) => i.id === imageId);
                if (img) setSelectedImage(img);
              }}
            />
          </CardContent>
        </Card>

        {/* Window/Level controls */}
        <Card>
          <CardHeader className="pb-2">
            <CardTitle className="text-sm">{t('viewer.windowLevel')}</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-sm text-muted-foreground">
              使用鼠标拖拽调整窗宽窗位
            </div>
          </CardContent>
        </Card>
      </div>
    </div>
  );
}

